-- Generated from ../data/porra-data.js

begin;

create extension if not exists pgcrypto;

delete from public.knockout_predictions;
delete from public.mini_answers;
delete from public.match_predictions;
delete from public.pool_submissions;
delete from public.pool_group_teams;
delete from public.fixtures;
delete from public.mini_questions;
delete from public.knockout_slots;
delete from public.pool_members;
delete from public.pool_groups;
delete from public.pools;
delete from public.teams;
delete from public.profiles;
delete from auth.identities;
delete from auth.users;

on conflict (id) do update set
  email = excluded.email,
  encrypted_password = excluded.encrypted_password,
  email_confirmed_at = excluded.email_confirmed_at,
  raw_app_meta_data = excluded.raw_app_meta_data,
  raw_user_meta_data = excluded.raw_user_meta_data,
  updated_at = excluded.updated_at;

on conflict (id) do update set
  provider_id = excluded.provider_id,
  user_id = excluded.user_id,
  identity_data = excluded.identity_data,
  provider = excluded.provider,
  updated_at = excluded.updated_at;

on conflict (id) do update set
  email = excluded.email,
  display_name = excluded.display_name,
  is_platform_admin = excluded.is_platform_admin,
  updated_at = excluded.updated_at;

on conflict (id) do update set
  slug = excluded.slug,
  name = excluded.name,
  edition_name = excluded.edition_name,
  status = excluded.status,
  lock_at = excluded.lock_at,
  group_exact_points = excluded.group_exact_points,
  group_sign_points = excluded.group_sign_points,
  created_by = excluded.created_by,
  updated_at = now();

on conflict (pool_id, email) do update set
  user_id = excluded.user_id,
  display_name = excluded.display_name,
  role = excluded.role;

on conflict (name) do update set
  short_name = excluded.short_name,
  code = excluded.code,
  flag_emoji = excluded.flag_emoji;

on conflict (pool_id, letter) do update set
  name = excluded.name,
  sort_order = excluded.sort_order;

on conflict (group_id, team_id) do update set
  sort_order = excluded.sort_order;

on conflict (pool_id, slot_key) do update set
  group_id = excluded.group_id,
  stage = excluded.stage,
  home_team_id = excluded.home_team_id,
  away_team_id = excluded.away_team_id,
  kickoff_at = excluded.kickoff_at,
  status = excluded.status,
  home_score = excluded.home_score,
  away_score = excluded.away_score,
  sort_order = excluded.sort_order,
  updated_at = now();

on conflict (user_id, fixture_id) do update set
  pool_id = excluded.pool_id,
  home_score = excluded.home_score,
  away_score = excluded.away_score,
  submitted_at = excluded.submitted_at,
  updated_at = excluded.updated_at;

on conflict (pool_id, sort_order) do update set
  label = excluded.label,
  field_type = excluded.field_type,
  points = excluded.points,
  options = excluded.options,
  sort_order = excluded.sort_order,
  updated_at = now();

on conflict (user_id, question_id) do update set
  pool_id = excluded.pool_id,
  answer = excluded.answer,
  submitted_at = excluded.submitted_at,
  updated_at = excluded.updated_at;

on conflict (pool_id, slot_key) do update set
  stage = excluded.stage,
  label = excluded.label,
  sort_order = excluded.sort_order,
  updated_at = now();

on conflict (user_id, slot_id) do update set
  pool_id = excluded.pool_id,
  team_id = excluded.team_id,
  submitted_at = excluded.submitted_at,
  updated_at = excluded.updated_at;

on conflict (pool_id, user_id, section) do update set
  status = excluded.status,
  submitted_at = excluded.submitted_at,
  updated_at = excluded.updated_at;

-- Admin real: asegura que morgadoluengo@gmail.com es platform admin si ya existe en Auth
select id, email, coalesce(raw_user_meta_data->>'display_name', 'MORGADO'), true
from auth.users
where email = 'morgadoluengo@gmail.com'
on conflict (id) do update
  set is_platform_admin = true;

commit;
